import hashlib

def deduplicate_exact(texts: list[str]) -> tuple[list[str], dict[str, int]]:
    """Remove exact duplicates. Returns unique texts and a hash-to-first-index map."""
    seen: dict[str, int] = {}
    unique = []
    for i, text in enumerate(texts):
        h = hashlib.sha256(text.encode()).hexdigest()
        if h not in seen:
            seen[h] = i
            unique.append(text)
    return unique, seen

from sklearn.feature_extraction.text import TfidfVectorizer from sklearn.metrics.pairwise import cosine_similarity
def deduplicate_texts(texts: list[str], threshold: float = 0.95) -> list[str]: """Remove near-duplicate texts before embedding.""" vectorizer = TfidfVectorizer() tfidf_matrix = vectorizer.fit_transform(texts)
unique_texts = [] for i, text in enumerate(texts): if not unique_texts: unique_texts.append(text) continue
# Compare with existing unique texts current_vec = tfidf_matrix[i] existing_vecs = vectorizer.transform(unique_texts) similarities = cosine_similarity(current_vec, existing_vecs)[0]
if max(similarities) < threshold: unique_texts.append(text)
return unique_texts
